	] <-- [
	Factories
	]

	[
	TestDataTypes.Patterns
	] <-- [
	TestDataTypes.Models.Specialized
	]
	]


	[Portamical.Core] <-- 
	[<package> Portamical
	|
	[<abstract>TestBases]
	[<static>Converters]
	[<abstract>Assertions]

	// diagram

	[
	Converters
	] <-- [
	TestBases
	]
	]

	[Portamical] <--
	[<package> Portamical.MSTest
